#include <bits/stdc++.h>
using namespace std;
int n,a[100005],b[100005];
int main(){
	//freopen("bamboo.in","r",stdin);
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d%d",&a[i],&b[i]);
        b[i]=max(b[i],a[i]-b[i]);
    }
    sort(b+1,b+n+1);
    sort(a+1,a+n+1);
    printf("%d",max(b[n]+b[n-1],a[n]));
    return 0;
}
